package record

import (
	"strconv"
)

// Helper functions: Create common vertical operation instances

// NewSumVerticalOperation creates a new sum vertical operation instance
func NewSumVerticalOperation(field string, newField string) *CommonVerticalOperation {
	return NewCommonVerticalOperation("sum", field, newField, nil)
}

// NewAvgVerticalOperation creates a new average vertical operation instance
func NewAvgVerticalOperation(field string, newField string) *CommonVerticalOperation {
	return NewCommonVerticalOperation("avg", field, newField, nil)
}

// NewCountVerticalOperation creates a new count vertical operation instance
func NewCountVerticalOperation(field string, newField string) *CommonVerticalOperation {
	return NewCommonVerticalOperation("count", field, newField, nil)
}

// NewMaxVerticalOperation creates a new max vertical operation instance
func NewMaxVerticalOperation(field string, newField string) *CommonVerticalOperation {
	return NewCommonVerticalOperation("max", field, newField, nil)
}

// NewMinVerticalOperation creates a new min vertical operation instance
func NewMinVerticalOperation(field string, newField string) *CommonVerticalOperation {
	return NewCommonVerticalOperation("min", field, newField, nil)
}

// NewGroupVerticalOperation creates a new group vertical operation instance
func NewGroupVerticalOperation(field string, newField string) *CommonVerticalOperation {
	return NewCommonVerticalOperation("group", field, newField, nil)
}

// VerticalOperation defines the interface for vertical operations
// Performs operations on multiple records (vertical) and returns the result
// NewField() and the returned any will be added as a new field in record map[string]any
type VerticalOperation interface {
	// Evaluate performs the operation on multiple records and returns the result
	Evaluate(records Records) any
	// NewField returns the name of the new field generated by the operation
	NewField() string
}

// CommonVerticalOperation implements common vertical operations
// Supports operations like sum, avg, count, max, min on multiple records
// Operation result will be added as a new field to the records

type CommonVerticalOperation struct {
	opType   string         // Operation type: sum, avg, count, max, min
	field    string         // Field to perform operation on
	newField string         // New field name generated by the operation
	args     map[string]any // Additional arguments
}

// NewCommonVerticalOperation creates a new common vertical operation instance
// opType: Operation type, e.g., sum, avg, count, max, min
// field: Field to perform operation on
// newField: New field name generated by the operation
// args: Additional arguments
func NewCommonVerticalOperation(opType string, field string, newField string, args map[string]any) *CommonVerticalOperation {
	if args == nil {
		args = make(map[string]any)
	}
	return &CommonVerticalOperation{
		opType:   opType,
		field:    field,
		newField: newField,
		args:     args,
	}
}

// Evaluate performs vertical operation on multiple records and returns the result
// records: Records to perform operation on
func (op *CommonVerticalOperation) Evaluate(records Records) any {
	if len(records) == 0 {
		return nil
	}

	switch op.opType {
	case "sum":
		return op.sumRecords(records)
	case "avg":
		return op.avgRecords(records)
	case "count":
		return op.countRecords(records)
	case "max":
		return op.maxRecords(records)
	case "min":
		return op.minRecords(records)
	case "group":
		return op.groupRecords(records)
	default:
		return nil
	}
}

// NewField returns the name of the new field generated by the operation
func (op *CommonVerticalOperation) NewField() string {
	return op.newField
}

// sumRecords calculates the sum of a field across multiple records
func (op *CommonVerticalOperation) sumRecords(records Records) any {
	sum := 0.0
	for _, record := range records {
		if val, ok := record[op.field]; ok {
			sum += toFloat64(val)
		}
	}
	return sum
}

// avgRecords calculates the average of a field across multiple records
func (op *CommonVerticalOperation) avgRecords(records Records) any {
	if len(records) == 0 {
		return 0.0
	}

	sum := 0.0
	count := 0
	for _, record := range records {
		if _, ok := record[op.field]; ok {
			sum += toFloat64(record[op.field])
			count++
		}
	}

	if count == 0 {
		return 0.0
	}
	return sum / float64(count)
}

// countRecords counts the number of records with a non-nil value in the specified field
func (op *CommonVerticalOperation) countRecords(records Records) any {
	count := 0
	for _, record := range records {
		if _, ok := record[op.field]; ok {
			count++
		}
	}
	return count
}

// maxRecords finds the maximum value of a field across multiple records
func (op *CommonVerticalOperation) maxRecords(records Records) any {
	if len(records) == 0 {
		return 0.0
	}

	maxVal := 0.0
	first := true
	for _, record := range records {
		if val, ok := record[op.field]; ok {
			floatVal := toFloat64(val)
			if first || floatVal > maxVal {
				maxVal = floatVal
				first = false
			}
		}
	}
	return maxVal
}

// minRecords finds the minimum value of a field across multiple records
func (op *CommonVerticalOperation) minRecords(records Records) any {
	if len(records) == 0 {
		return 0.0
	}

	minVal := 0.0
	first := true
	for _, record := range records {
		if val, ok := record[op.field]; ok {
			floatVal := toFloat64(val)
			if first || floatVal < minVal {
				minVal = floatVal
				first = false
			}
		}
	}
	return minVal
}

// groupRecords groups records by the specified field and returns grouped records
// Returns a map where keys are field values and values are grouped records
func (op *CommonVerticalOperation) groupRecords(records Records) any {
	groups := make(map[any]Records)
	for _, record := range records {
		if val, ok := record[op.field]; ok {
			groups[val] = append(groups[val], record)
		}
	}
	return groups
}

// toFloat64 converts any type to float64
func toFloat64(val any) float64 {
	switch v := val.(type) {
	case int:
		return float64(v)
	case int8:
		return float64(v)
	case int16:
		return float64(v)
	case int32:
		return float64(v)
	case int64:
		return float64(v)
	case uint:
		return float64(v)
	case uint8:
		return float64(v)
	case uint16:
		return float64(v)
	case uint32:
		return float64(v)
	case uint64:
		return float64(v)
	case float32:
		return float64(v)
	case float64:
		return v
	case bool:
		if v {
			return 1.0
		}
		return 0.0
	case string:
		// Try to convert string to number
		if f, err := strconv.ParseFloat(v, 64); err == nil {
			return f
		}
		return 0.0
	default:
		return 0.0
	}
}
